Based on the commit message, the root cause and the patch provided below, you need to:

1. explain how the bug occurs, including all code statements that are most likely to lead to the bug and why. 
2. explain how the bug is fixed, including code statements fixing the bug and why. 

You must include one or more code statements in point 1 and 2.
Code statements included in point 1 should be as brief as possible, only include the ones that are most related to the root cause and  the number of code statements may not exceed 3.


Here is the commit message:
Fix bug #71923 - integer overflow in ZipArchive::getFrom*

Here is the root cause:
The bug is caused by the use of `zend_string_alloc(len, 0)` for memory allocation, which does not account for potential integer overflow when calculating the size of the buffer. If `len` is a large value, it could lead to an allocation request that exceeds the maximum allowable size, resulting in an overflow and potentially causing memory corruption or crashes when the buffer is accessed. The use of `zend_string_safe_alloc` mitigates this risk by ensuring safe allocation practices.

Here is the patch:
    Read from an open directory entry */
 static PHP_NAMED_FUNCTION(zif_zip_entry_read)
 {
 	zval * zip_entry;
 	zend_long len = 0;
 	zip_read_rsrc * zr_rsrc;
 	zend_string *buffer;
 	int n = 0;

 	if (zend_parse_parameters(ZEND_NUM_ARGS(), "r|l", &zip_entry, &len) == FAILURE) {
 		return;
 	}

 	if ((zr_rsrc = (zip_read_rsrc *)zend_fetch_resource(Z_RES_P(zip_entry), le_zip_entry_name, le_zip_entry)) == NULL) {
 		RETURN_FALSE;
 	}

 	if (len <= 0) {
 		len = 1024;
 	}

 	if (zr_rsrc->zf) {
-		buffer = zend_string_alloc(len, 0);
+		buffer = zend_string_safe_alloc(1, len, 0, 0);
 		n = zip_fread(zr_rsrc->zf, ZSTR_VAL(buffer), ZSTR_LEN(buffer));
 		if (n > 0) {
 			ZSTR_VAL(buffer)[n] = '\0';
 			ZSTR_LEN(buffer) = n;
 			RETURN_NEW_STR(buffer);
 		} else {
 			zend_string_free(buffer);
 			RETURN_EMPTY_STRING()
 		}
 	} else {
 		RETURN_FALSE;
 	}
 }
 /* }}} */

 static void php_zip_get_from(INTERNAL_FUNCTION_PARAMETERS, int type) /* {{{ */
 {
 	struct zip *intern;
 	zval *self = getThis();

 	struct zip_stat sb;
 	struct zip_file *zf;

 	zend_long index = -1;
 	zend_long flags = 0;
 	zend_long len = 0;

 	zend_string *filename;
 	zend_string *buffer;

 	int n = 0;

 	if (!self) {
 		RETURN_FALSE;
 	}

 	ZIP_FROM_OBJECT(intern, self);

 	if (type == 1) {
 		if (zend_parse_parameters(ZEND_NUM_ARGS(), "P|ll", &filename, &len, &flags) == FAILURE) {
 			return;
 		}
 		PHP_ZIP_STAT_PATH(intern, ZSTR_VAL(filename), ZSTR_LEN(filename), flags, sb);
 	} else {
 		if (zend_parse_parameters(ZEND_NUM_ARGS(), "l|ll", &index, &len, &flags) == FAILURE) {
 			return;
 		}
 		PHP_ZIP_STAT_INDEX(intern, index, 0, sb);
 	}

 	if (sb.size < 1) {
 		RETURN_EMPTY_STRING();
 	}

 	if (len < 1) {
 		len = sb.size;
 	}
 	if (index >= 0) {
 		zf = zip_fopen_index(intern, index, flags);
 	} else {
 		zf = zip_fopen(intern, ZSTR_VAL(filename), flags);
 	}

 	if (zf == NULL) {
 		RETURN_FALSE;
 	}

-	buffer = zend_string_alloc(len, 0);
+	buffer = zend_string_safe_alloc(1, len, 0, 0);
 	n = zip_fread(zf, ZSTR_VAL(buffer), ZSTR_LEN(buffer));
 	if (n < 1) {
 		zend_string_free(buffer);
 		RETURN_EMPTY_STRING();
 	}

 	zip_fclose(zf);
 	ZSTR_VAL(buffer)[n] = '\0';
 	ZSTR_LEN(buffer) = n;
 	RETURN_NEW_STR(buffer);
 }
 /* }}} */


