	}

	if (entry_name_len == 0) {
		entry_name = filename->val;
		entry_name_len = filename->len;
	}

	if (php_zip_add_file(intern, filename->val, filename->len, entry_name, entry_name_len, 0, 0 TSRMLS_CC) < 0) {
		RETURN_FALSE;
	} else {
		RETURN_TRUE;
	}
}
