/* {{{ proto int ZipArchive::locateName(string filename[, int flags])
Returns the index of the entry named filename in the archive */
static ZIPARCHIVE_METHOD(locateName)
{
	struct zip *intern;
	zval *self = getThis();
	php_int_t flags = 0;
	php_int_t idx = -1;
	zend_string *name;

	if (!self) {
		RETURN_FALSE;
	}

	ZIP_FROM_OBJECT(intern, self);

	if (zend_parse_parameters(ZEND_NUM_ARGS() TSRMLS_CC, "P|i", &name, &flags) == FAILURE) {
		return;
	}

	if (name->len < 1) {
		RETURN_FALSE;
	}

	idx = (php_int_t)zip_name_locate(intern, (const char *)name->val, flags);

	if (idx >= 0) {
		RETURN_INT(idx);
	} else {
		RETURN_FALSE;
	}
